namespace BgCommon.Script.Runtime.Configuration;/// <summary>/// 表示脚本模板的配置信息类./// </summary>public class TemplateConfig : ScriptConfig{    /// <summary>    /// Initializes a new instance of the <see cref="TemplateConfig"/> class.    /// </summary>    public TemplateConfig()        : base()    {        this.Extension = ExtensionTemplate;    }    /// <summary>    /// Initializes a new instance of the <see cref="TemplateConfig"/> class.    /// </summary>    /// <param name="directory">文件存储路径.</param>    /// <param name="referLibsPath">引用程序集所在路径.</param>    /// <param name="extension">文件扩展名.</param>    /// <param name="name">配置文件名称.</param>    public TemplateConfig(        string directory,        string referLibsPath,        string? extension = null,        string? name = null)        : base(directory, referLibsPath, extension, name)    {        this.Extension = extension ?? ExtensionTemplate;    }}